package com.chrisb97.warehouse.controller;
import com.chrisb97.warehouse.config.AppContext;import com.chrisb97.warehouse.model.*;import com.chrisb97.warehouse.util.AlertUtil;import javafx.beans.property.SimpleStringProperty;import javafx.collections.*;import javafx.fxml.FXML;import javafx.scene.control.*;import java.util.*;
public class PickingController{@FXML private ComboBox<Product> productCombo;@FXML private TextField quantityField;@FXML private CheckBox returnCheck;@FXML private TableView<PickingRequest> requestTable;@FXML private TableColumn<PickingRequest,String> requestProductColumn,requestQuantityColumn,requestLocationColumn;@FXML private ListView<String> routeList;@FXML private Label distanceLabel;private final ObservableList<PickingRequest> requests=FXCollections.observableArrayList();
@FXML public void initialize(){productCombo.setItems(FXCollections.observableArrayList(AppContext.getInstance().products().activeProducts()));requestProductColumn.setCellValueFactory(d->new SimpleStringProperty(d.getValue().product().getSku()+" — "+d.getValue().product().getName()));requestQuantityColumn.setCellValueFactory(d->new SimpleStringProperty(String.valueOf(d.getValue().requestedQuantity())));requestLocationColumn.setCellValueFactory(d->new SimpleStringProperty(d.getValue().product().getLocationCode()));requestTable.setItems(requests);}
@FXML private void addItem(){try{Product p=productCombo.getValue();if(p==null)throw new IllegalArgumentException("Select a product.");int q=Integer.parseInt(quantityField.getText());if(q<=0)throw new IllegalArgumentException("Quantity must be positive.");requests.removeIf(r->Objects.equals(r.product().getId(),p.getId()));requests.add(new PickingRequest(p,q));quantityField.clear();}catch(NumberFormatException e){AlertUtil.error("Invalid quantity","Quantity must be an integer.");}catch(RuntimeException e){AlertUtil.error("Cannot add item",e.getMessage());}}
@FXML private void removeItem(){PickingRequest selected=requestTable.getSelectionModel().getSelectedItem();if(selected!=null)requests.remove(selected);}
@FXML private void generate(){try{PickingRoute route=AppContext.getInstance().picking().generate(List.copyOf(requests),AppContext.getInstance().locations().activeLocations(),returnCheck.isSelected());ObservableList<String> lines=FXCollections.observableArrayList("Start — Entrance (0, 0)");for(PickingStop s:route.stops()){String products=s.items().stream().map(i->i.product().getSku()+" × "+i.requestedQuantity()).reduce((a,b)->a+", "+b).orElse("");lines.add(s.pickingOrder()+". "+s.location().getCode()+" — "+products);}if(route.returnsToEntrance())lines.add("Return to entrance");routeList.setItems(lines);distanceLabel.setText(route.totalDistance()+" units");}catch(RuntimeException e){AlertUtil.error("Could not generate route",e.getMessage());}}
@FXML private void clear(){requests.clear();routeList.getItems().clear();distanceLabel.setText("0 units");}}
